// Sistema de roles y permisos para el ERP Multi-Compañía

export const ROLES = {
  SUPER_ADMIN: 'super_admin',    // Tú - Control total de todo
  COMPANY_ADMIN: 'company_admin',  // Admin de compañía - Control total de su compañía
  MANAGER: 'manager',              // Gerente - Gestión de producción y procesos
  OPERATOR: 'operator',            // Operador - Solo producción
  QUALITY: 'quality'               // Calidad - Solo control de calidad
};

export const PERMISSIONS = {
  // Permisos de Super Admin
  SUPER_ADMIN: [
    'view_all_companies',
    'create_companies',
    'edit_companies',
    'delete_companies',
    'create_users',
    'edit_users',
    'delete_users',
    'assign_roles',
    'view_all_data',
    'system_settings'
  ],

  // Permisos de Company Admin
  COMPANY_ADMIN: [
    'view_own_company',
    'edit_own_company',
    'create_users_in_company',
    'edit_users_in_company',
    'delete_users_in_company',
    'assign_roles_in_company',
    'view_all_company_data',
    'manage_products',
    'manage_customers',
    'manage_processes',
    'manage_production',
    'manage_quality',
    'manage_laboratory',
    'manage_inventory',
    'company_settings'
  ],

  // Permisos de Manager
  MANAGER: [
    'view_own_company',
    'manage_products',
    'manage_customers',
    'manage_processes',
    'manage_production',
    'view_quality_data',
    'view_laboratory_data',
    'view_inventory_data'
  ],

  // Permisos de Operator
  OPERATOR: [
    'view_own_company',
    'view_production_orders',
    'create_production_orders',
    'edit_production_orders',
    'view_inventory_data',
    'update_inventory'
  ],

  // Permisos de Quality
  QUALITY: [
    'view_own_company',
    'view_quality_controls',
    'create_quality_controls',
    'edit_quality_controls',
    'view_laboratory_data',
    'create_laboratory_analysis',
    'edit_laboratory_analysis'
  ]
};

export const ROLE_HIERARCHY = {
  [ROLES.SUPER_ADMIN]: 5,
  [ROLES.COMPANY_ADMIN]: 4,
  [ROLES.MANAGER]: 3,
  [ROLES.OPERATOR]: 2,
  [ROLES.QUALITY]: 2
};

export const ROLE_DISPLAY_NAMES = {
  [ROLES.SUPER_ADMIN]: 'Super Administrador',
  [ROLES.COMPANY_ADMIN]: 'Administrador de Compañía',
  [ROLES.MANAGER]: 'Gerente',
  [ROLES.OPERATOR]: 'Operador',
  [ROLES.QUALITY]: 'Control de Calidad'
};

// Clase para manejar permisos
export class PermissionManager {
  static hasRole(userRole, requiredRole) {
    const userLevel = ROLE_HIERARCHY[userRole] || 0;
    const requiredLevel = ROLE_HIERARCHY[requiredRole] || 0;
    return userLevel >= requiredLevel;
  }

  static hasPermission(userRole, permission) {
    const permissions = PERMISSIONS[userRole] || [];
    return permissions.includes(permission);
  }

  static canAccessResource(userRole, resource) {
    const resourcePermissions = {
      'dashboard': ['view_own_company', 'view_all_data'],
      'companies': ['view_all_companies', 'create_companies'],
      'users': ['create_users', 'create_users_in_company'],
      'products': ['manage_products'],
      'customers': ['manage_customers'],
      'processes': ['manage_processes'],
      'production': ['manage_production', 'view_production_orders'],
      'quality': ['manage_quality', 'view_quality_data'],
      'laboratory': ['manage_laboratory', 'view_laboratory_data'],
      'inventory': ['manage_inventory', 'view_inventory_data'],
      'settings': ['system_settings', 'company_settings']
    };

    const requiredPermissions = resourcePermissions[resource] || [];
    const userPermissions = PERMISSIONS[userRole] || [];

    return requiredPermissions.some(permission => 
      userPermissions.includes(permission)
    );
  }

  static getAccessibleResources(userRole) {
    const allResources = [
      'dashboard', 'companies', 'users', 'products', 'customers', 
      'processes', 'production', 'quality', 'laboratory', 'inventory', 'settings'
    ];

    return allResources.filter(resource => 
      this.canAccessResource(userRole, resource)
    );
  }

  static canManageUser(managerRole, targetUserRole) {
    return this.hasRole(managerRole, targetUserRole);
  }
}

export default PermissionManager;
